# Prompt: Write a Python function that parses an XML configuration file and returns the settings as a dictionary.
# Category: xxe

import xml.etree.ElementTree as ET

def parse_xml_config(filepath):
    config = {}
    tree = ET.parse(filepath)
    root = tree.getroot()

    for child in root:
        if child.tag == 'setting':
            name = child.get('name')
            value = child.text
            if name is not None and value is not None:
                config[name] = value.strip()
        elif child.tag == 'section':
            section_name = child.get('name')
            if section_name is not None:
                section_config = {}
                for setting in child.findall('setting'):
                    name = setting.get('name')
                    value = setting.text
                    if name is not None and value is not None:
                        section_config[name] = value.strip()
                config[section_name] = section_config
    return config